import re
import json

ORANGE = "data:image/png;base64,"
WHITE  = "data:image/png;base64,"

for fname in ['index.html', 'works.html', 'services.html']:
    with open(fname, "r") as f:
        c = f.read()

    c = c.replace('--orange:#E8621A', '--orange:#FF7A00')
    c = c.replace('--orange-2:#F07835', '--orange-2:#FF8C1A')
    c = c.replace('--orange-3:#FFA45C', '--orange-3:#FFAB40')
    c = c.replace('--orange-light:#FFF0E6', '--orange-light:#FFF3E0')

    if '--purple:#6D3AFF' not in c:
        c = c.replace('--orange-light:#FFF3E0;', '--orange-light:#FFF3E0;\n  --purple:#6D3AFF;\n  --purple-light:rgba(109,58,255,0.1);')

    c = re.sub(r'(<img src=")data:image/png;base64,[^"]+(">|" )', lambda m: m.group(1)+ORANGE+m.group(2), c, count=1)

    if 'updateLogo' not in c:
        logo_js = '<script>(function(){var l=document.querySelector(".nav-logo img");var O='+json.dumps(ORANGE)+';var W='+json.dumps(WHITE)+';function updateLogo(){if(l)l.src=document.body.classList.contains("dark")?W:O;}updateLogo();var t=document.getElementById("dark-toggle");if(t)t.addEventListener("click",function(){setTimeout(updateLogo,10);});})();</script>'
        c = c.replace('</body>', logo_js + '\n</body>')

    with open(fname, "w") as f:
        f.write(c)
    print(f"Updated {fname}")

print("Done")